Pushout (functor_sigma f (fun a : A => idmap))
  (functor_sigma g (fun a : A => pod_e Pe a)) ->
{x : _ & fam_podescent Pe x}

Pushout (functor_sigma f (fun a : A => idmap))
  (functor_sigma g (fun a : A => pod_e Pe a)) ->
{x : _ & fam_podescent Pe x}

forall (x : Pushout f g) (px : fam_podescent Pe x),
Pushout_rec {x : _ & fam_podescent Pe x}
  (fun pat : {x : _ & pod_faml Pe x} =>
   let x0 := pat in let b := x0.1 in let pb := x0.2 in (pushl b; pb))
  (fun pat : {x : _ & pod_famr Pe x} =>
   let x0 := pat in let c := x0.1 in let pc := x0.2 in (pushr c; pc))
  (fun a0 : {H0 : A & pod_faml Pe (f H0)} => flatten_pod_glue a0.1 1)
  (sig_rec
     (podepdescent_rec
        {|
          poddcs_sectl := fun (b : B) (pb : pod_faml Pe b) => pushl (b; pb);
          poddcs_sectr := fun (c : C) (pc : pod_famr Pe c) => pushr (c; pc);
          poddcs_e := fun (a : A) (pf : pod_faml Pe (f a)) => pglue (a; pf)
        |})
     (x; px)) =
(x; px)
